var BASE_URL = "https://flixhq.to";
var HEADERS = {
  "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36",
  "Referer": BASE_URL + "/",
  "X-Requested-With": "XMLHttpRequest",
  "Accept": "application/json, text/plain, */*"
};

class Provider {
  getSettings() {
    return { servers: ["UpCloud", "Vidcloud", "AKCloud"] };
  }

  async findMovieStreams(opts) {
    var results = [];
    var lastErr = "Unknown error";
    try {
      lastErr = "Searching for " + opts.title;
      var slug = opts.title.replace(/[^a-zA-Z0-9\s]/g, "").trim().replace(/\s+/g, "-").toLowerCase();
      var searchHtml = await fetch(BASE_URL + "/search/" + slug, { headers: HEADERS }).then(function(r) { return r.text(); });

      var targetId = "";
      var cleanTitle = opts.title.replace(/[^a-zA-Z0-9]/g, "").toLowerCase();

      var candidates = [];
      var blocks = searchHtml.split("flw-item");
      for (var b = 1; b < blocks.length; b++) {
         var block = blocks[b];
         var aMatch = block.match(/href="\/movie\/watch-([^"]+)-(\d+)"/);
         var yMatch = block.match(/fdi-item[^>]*>\s*((?:19|20)\d{2})\s*</);
         if (!yMatch) { yMatch = block.match(/>\s*((?:19|20)\d{2})\s*<\/span>/); }
         if (!yMatch) { var allYears = block.match(/(?:19|20)\d{2}/g); if (allYears) { for (var yi = 0; yi < allYears.length; yi++) { var y = parseInt(allYears[yi], 10); if (y >= 1950 && y <= 2030) { yMatch = [null, allYears[yi]]; break; } } } }

         if (aMatch) {
            var titleSlug = aMatch[1].replace(/[^a-zA-Z0-9]/g, "").toLowerCase();
            var resId = aMatch[2];
            var resYear = yMatch ? parseInt(yMatch[1], 10) : 0;
            console.log("[flixhq] Candidate found: " + titleSlug + " (" + resYear + ") ID: " + resId);

            if (titleSlug === cleanTitle || titleSlug.indexOf(cleanTitle) !== -1 || cleanTitle.indexOf(titleSlug) !== -1) {
               candidates.push({ id: resId, slug: titleSlug, year: resYear, exact: titleSlug === cleanTitle });
            }
         } else {
            var altMatch = block.match(/href="\/movie\/([^"]+)-(\d+)"/);
            if (altMatch) {
               var tSlug = altMatch[1].replace(/[^a-zA-Z0-9]/g, "").toLowerCase();
               var rId = altMatch[2];
               var rYear = yMatch ? parseInt(yMatch[1], 10) : 0;
               if (tSlug.indexOf(cleanTitle) !== -1) {
                  candidates.push({ id: rId, slug: tSlug, year: rYear, exact: false });
               }
            }
         }
      }

      console.log("[flixhq] Found " + candidates.length + " title-matching candidates");

      if (candidates.length > 0) {
          if (opts.year) {
              for (var ci = 0; ci < candidates.length; ci++) {
                  if (candidates[ci].year === opts.year) {
                      targetId = candidates[ci].id;
                      console.log("[flixhq] Exact year match found for " + opts.title + " (" + opts.year + "): " + targetId);
                      break;
                  }
              }
          }
          if (!targetId) {
              var exactMatches = [];
              for (var ci = 0; ci < candidates.length; ci++) {
                  if (candidates[ci].exact) {
                      exactMatches.push(candidates[ci]);
                  }
              }
              if (exactMatches.length > 0) {
                  exactMatches.sort(function(a, b) { return parseInt(b.id, 10) - parseInt(a.id, 10); });
                  targetId = exactMatches[0].id;
                  console.log("[flixhq] Using best exact title match (highest ID): " + targetId);
              }
          }
          if (!targetId) {
              candidates.sort(function(a, b) { return parseInt(b.id, 10) - parseInt(a.id, 10); });
              targetId = candidates[0].id;
              console.log("[flixhq] Using best partial match (highest ID): " + targetId);
          }
      }

      if (!targetId) {
          console.error("[flixhq] No ID found for " + cleanTitle + " year: " + opts.year);
          return { provider: "flixhq-movies", sources: [] };
      }

      lastErr = "Fetching episodes for " + targetId;
      var epHtml = await fetch(BASE_URL + "/ajax/movie/episodes/" + targetId, { headers: HEADERS }).then(function(r) { return r.text(); });
      if (epHtml.trim().charAt(0) === "{") { try { epHtml = JSON.parse(epHtml).html || epHtml; } catch(e) {} }

      var epMatch = epHtml.match(/id=\"episode-servers-(\d+)\"/);
      var episodeId = epMatch ? epMatch[1] : targetId;

      results = await this.extractServers(episodeId, epHtml, opts.title);
    } catch (e) {
      console.error("[flixhq] Error at " + lastErr + " : " + String(e));
    }
    return { provider: "flixhq-movies", sources: results };
  }

  async findTvShowStreams(opts) {
    var results = [];
    var lastErr = "Unknown error";
    try {
      lastErr = "Searching for TV show " + opts.title;
      var slug = opts.title.replace(/[^a-zA-Z0-9\s]/g, "").trim().replace(/\s+/g, "-").toLowerCase();
      var searchHtml = await fetch(BASE_URL + "/search/" + slug, { headers: HEADERS }).then(function(r) { return r.text(); });

      var targetId = "";
      var cleanTitle = opts.title.replace(/[^a-zA-Z0-9]/g, "").toLowerCase();

      var candidates = [];
      var blocks = searchHtml.split("flw-item");
      for (var b = 1; b < blocks.length; b++) {
         var block = blocks[b];
         var aMatch = block.match(/href="\/tv\/watch-([^"]+)-(\d+)"/);
         var yMatch = block.match(/fdi-item[^>]*>\s*((?:19|20)\d{2})\s*</);
         if (!yMatch) { yMatch = block.match(/>\s*((?:19|20)\d{2})\s*<\/span>/); }
         if (!yMatch) { var allYears = block.match(/(?:19|20)\d{2}/g); if (allYears) { for (var yi = 0; yi < allYears.length; yi++) { var y = parseInt(allYears[yi], 10); if (y >= 1950 && y <= 2030) { yMatch = [null, allYears[yi]]; break; } } } }

         if (aMatch) {
            var titleSlug = aMatch[1].replace(/[^a-zA-Z0-9]/g, "").toLowerCase();
            var resId = aMatch[2];
            var resYear = yMatch ? parseInt(yMatch[1], 10) : 0;
            console.log("[flixhq-tv] Candidate found: " + titleSlug + " (" + resYear + ") ID: " + resId);

            if (titleSlug === cleanTitle || titleSlug.indexOf(cleanTitle) !== -1 || cleanTitle.indexOf(titleSlug) !== -1) {
               candidates.push({ id: resId, slug: titleSlug, year: resYear, exact: titleSlug === cleanTitle });
            }
         }
      }

      console.log("[flixhq-tv] Found " + candidates.length + " title-matching candidates");

      if (candidates.length > 0) {
          if (opts.year) {
              for (var ci = 0; ci < candidates.length; ci++) {
                  if (candidates[ci].year === opts.year) {
                      targetId = candidates[ci].id;
                      console.log("[flixhq-tv] Exact year match found for " + opts.title + " (" + opts.year + "): " + targetId);
                      break;
                  }
              }
          }
          if (!targetId) {
              var exactMatches = [];
              for (var ci = 0; ci < candidates.length; ci++) {
                  if (candidates[ci].exact) {
                      exactMatches.push(candidates[ci]);
                  }
              }
              if (exactMatches.length > 0) {
                  exactMatches.sort(function(a, b) { return parseInt(b.id, 10) - parseInt(a.id, 10); });
                  targetId = exactMatches[0].id;
                  console.log("[flixhq-tv] Using best exact title match (highest ID): " + targetId);
              }
          }
          if (!targetId) {
              candidates.sort(function(a, b) { return parseInt(b.id, 10) - parseInt(a.id, 10); });
              targetId = candidates[0].id;
              console.log("[flixhq-tv] Using best partial match (highest ID): " + targetId);
          }
      }

      if (!targetId) {
          console.error("[flixhq-tv] No TV show ID found for " + cleanTitle);
          return { provider: "flixhq-movies", sources: [] };
      }

      lastErr = "Fetching seasons for " + targetId;
      var seasonsHtml = await fetch(BASE_URL + "/ajax/v2/tv/seasons/" + targetId, { headers: HEADERS }).then(function(r) { return r.text(); });
      if (seasonsHtml.trim().charAt(0) === "{") { try { seasonsHtml = JSON.parse(seasonsHtml).html || seasonsHtml; } catch(e) {} }
      console.log("[flixhq-tv] Seasons HTML length: " + seasonsHtml.length);

      var seasonIds = [];
      var seasonIdRegex = /data-id="(\d+)"/g;
      var sMatch;
      while ((sMatch = seasonIdRegex.exec(seasonsHtml)) !== null) {
          seasonIds.push(sMatch[1]);
      }
      console.log("[flixhq-tv] Found " + seasonIds.length + " seasons: " + seasonIds.join(", "));

      if (seasonIds.length === 0) {
          console.error("[flixhq-tv] No seasons found");
          return { provider: "flixhq-movies", sources: [] };
      }

      var seasonIdx = opts.season - 1;
      if (seasonIdx < 0 || seasonIdx >= seasonIds.length) {
          console.error("[flixhq-tv] Season " + opts.season + " not available (only " + seasonIds.length + " seasons)");
          return { provider: "flixhq-movies", sources: [] };
      }

      var seasonId = seasonIds[seasonIdx];
      console.log("[flixhq-tv] Using season ID: " + seasonId + " for season " + opts.season);

      lastErr = "Fetching episodes for season " + opts.season;
      var episodesHtml = await fetch(BASE_URL + "/ajax/v2/season/episodes/" + seasonId, { headers: HEADERS }).then(function(r) { return r.text(); });
      if (episodesHtml.trim().charAt(0) === "{") { try { episodesHtml = JSON.parse(episodesHtml).html || episodesHtml; } catch(e) {} }
      console.log("[flixhq-tv] Episodes HTML length: " + episodesHtml.length);

      var episodeIds = [];
      var epIdRegex = /data-id="(\d+)"/g;
      var eMatch;
      while ((eMatch = epIdRegex.exec(episodesHtml)) !== null) {
          episodeIds.push(eMatch[1]);
      }
      console.log("[flixhq-tv] Found " + episodeIds.length + " episodes: " + episodeIds.slice(0, 5).join(", ") + (episodeIds.length > 5 ? "..." : ""));

      if (episodeIds.length === 0) {
          console.error("[flixhq-tv] No episodes found in season " + opts.season);
          return { provider: "flixhq-movies", sources: [] };
      }

      var epIdx = opts.episode - 1;
      if (epIdx < 0 || epIdx >= episodeIds.length) {
          console.error("[flixhq-tv] Episode " + opts.episode + " not available (only " + episodeIds.length + " episodes)");
          return { provider: "flixhq-movies", sources: [] };
      }

      var episodeId = episodeIds[epIdx];
      console.log("[flixhq-tv] Using episode ID: " + episodeId + " for S" + opts.season + "E" + opts.episode);

      lastErr = "Fetching servers for episode " + episodeId;
      var serversHtml = await fetch(BASE_URL + "/ajax/v2/episode/servers/" + episodeId, { headers: HEADERS }).then(function(r) { return r.text(); });
      if (serversHtml.trim().charAt(0) === "{") { try { serversHtml = JSON.parse(serversHtml).html || serversHtml; } catch(e) {} }

      results = await this.extractServers(episodeId, serversHtml, opts.title + " S" + opts.season + "E" + opts.episode);
    } catch (e) {
      console.error("[flixhq-tv] Error at " + lastErr + " : " + String(e));
    }
    return { provider: "flixhq-movies", sources: results };
  }

  async extractServers(episodeId, sHtml, mediaTitle) {
    var results = [];
    var lastErr = "Extracting servers";

    try {
      if (sHtml.indexOf("data-linkid=") === -1 && sHtml.indexOf("data-id=") === -1) {
          lastErr = "Fetching servers for " + episodeId;
          sHtml = await fetch(BASE_URL + "/ajax/v2/episode/servers/" + episodeId, { headers: HEADERS }).then(function(r) { return r.text(); });
          if (sHtml.trim().charAt(0) === "{") { try { sHtml = JSON.parse(sHtml).html || sHtml; } catch(e) {} }
      }

      var serverRegex1 = /(?:data-linkid|data-id)=["\'](\d+)["\'][^>]*title=["\']([^"\']+)["\']/g;
      var serverRegex2 = /title=["\']([^"\']+)["\'][^>]*(?:data-linkid|data-id)=["\'](\d+)["\']/g;
      var sm;
      var parsedServers = [];
      var seenIds = {};
      while ((sm = serverRegex1.exec(sHtml)) !== null) { if (!seenIds[sm[1]]) { seenIds[sm[1]] = true; parsedServers.push([sm[1], sm[2].trim()]); } }
      while ((sm = serverRegex2.exec(sHtml)) !== null) { if (!seenIds[sm[2]]) { seenIds[sm[2]] = true; parsedServers.push([sm[2], sm[1].trim()]); } }

      console.log("[flixhq] Found " + parsedServers.length + " servers");

      for (var i = 0; i < parsedServers.length; i++) {
        var serverId = parsedServers[i][0];
        var serverName = parsedServers[i][1];
        try {
          lastErr = "Fetching source " + serverId;
          var srcText = await fetch(BASE_URL + "/ajax/episode/sources/" + serverId, { headers: HEADERS }).then(function(r) { return r.text(); });
          var link = "";
          if (srcText.trim().charAt(0) === "{") {
              try { link = JSON.parse(srcText).link; } catch(e) {}
          }
          if (!link) { console.error("[flixhq] No link for server " + serverName); continue; }

          console.log("[flixhq] Server " + serverName + " embed: " + link);
          lastErr = "Extracting from " + link;

          var extracted = await this.extractMegaCloud(link);
          if (extracted && extracted.sources && extracted.sources.length > 0) {
             var parsedTracks = [];

             if (extracted.tracks && extracted.tracks.length > 0) {
                 for (var ti = 0; ti < extracted.tracks.length; ti++) {
                     var t = extracted.tracks[ti];
                     if (t.kind === "captions" || t.kind === "subtitles") {
                         parsedTracks.push({
                             id: "sub-native-" + ti,
                             url: t.file,
                             language: t.label || "Unknown",
                             label: t.label || "Unknown",
                             isDefault: ti === 0
                         });
                     }
                 }
             }

             for (var si = 0; si < extracted.sources.length; si++) {
                var s = extracted.sources[si];
                if (s.file) {
                   var embedOrigin = new URL(link).origin;
                   results.push({
                      server: serverName,
                      url: s.file,
                      type: s.type || "hls",
                      quality: "auto",
                      subtitles: parsedTracks,
                      headers: {
                         "Referer": embedOrigin + "/",
                         "Origin": embedOrigin,
                         "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36"
                      }
                   });
                   console.log("[flixhq] SUCCESS for " + serverName + ", Tracks: " + parsedTracks.length);
                }
             }
          }
        } catch (serverErr) {
          console.error("[flixhq] Server " + serverName + " failed: " + String(serverErr));
        }
      }
    } catch (e) {
      console.error("[flixhq] extractServers error: " + String(e));
    }
    return results;
  }

  async extractMegaCloud(embedUrl) {
    var urlUrl = new URL(embedUrl);
    var baseDomain = urlUrl.protocol + "//" + urlUrl.host + "/";

    var embedHeaders = {
      "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36",
      "Referer": BASE_URL + "/",
      "Accept-Language": "en-US,en;q=0.9"
    };

    var html = await fetch(embedUrl, { headers: embedHeaders }).then(function(r) { return r.text(); });

    if (html.indexOf("File not found") !== -1 || html.indexOf("404 Not Found") !== -1) {
      return null;
    }

    var fileIdMatch = html.match(/<title>\s*File\s+#([a-zA-Z0-9]+)\s*-/i);
    var fileId = fileIdMatch ? fileIdMatch[1] : "";
    if (!fileId) {
       var parts = urlUrl.pathname.split("/");
       for (var i=0; i<parts.length; i++) {
          if (parts[i].length > 8 && parts[i].indexOf("?") === -1) { fileId = parts[i]; break; }
       }
    }

    var nonce = null;
    var match48 = html.match(/\b[a-zA-Z0-9]{48}\b/);
    if (match48) { nonce = match48[0]; }
    else {
      var srcMatchRegex = /['"]([A-Za-z0-9]{16})['"]/g;
      var srcMatches = [];
      var m;
      while ((m = srcMatchRegex.exec(html)) !== null) {
        srcMatches.push(m[1]);
      }
      if (srcMatches.length >= 3) {
        nonce = srcMatches[0] + srcMatches[1] + srcMatches[2];
      }
    }

    if (!fileId || !nonce) return null;

    var apiHeaders = {
      "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36",
      "Referer": embedUrl,
      "X-Requested-With": "XMLHttpRequest",
      "Accept": "application/json, text/javascript, */*; q=0.01"
    };

    var embedPrefix = "embed-1";
    if (embedUrl.indexOf("/embed-2/") !== -1) embedPrefix = "embed-2";
    else if (embedUrl.indexOf("/embed-4/") !== -1) embedPrefix = "embed-4";

    var apiUrl = baseDomain + embedPrefix + "/ajax/e-1/getSources?id=" + fileId + "&_k=" + nonce;
    var apiText = await fetch(apiUrl, { headers: apiHeaders }).then(function(r) { return r.text(); });

    if (!apiText || apiText.indexOf("<!DOCTYPE html>") !== -1 || apiText.indexOf("error") !== -1) {
        apiUrl = baseDomain + embedPrefix + "/v3/e-1/getSources?id=" + fileId + "&_k=" + nonce;
        apiText = await fetch(apiUrl, { headers: apiHeaders }).then(function(r) { return r.text(); });
    }

    try {
      var data = JSON.parse(apiText);
      if (data && data.sources) {
          if (typeof data.sources === "string") {
              var decrypted = this.decrypt(data.sources, "s8d7hf687sdf");
              if (decrypted) data.sources = JSON.parse(decrypted);
          }
          return data;
      }
    } catch(e) {}
    return null;
  }

  decrypt(str, key) {
      if (!str) return "";
      try {
          if (typeof CryptoJS !== "undefined") {
              return CryptoJS.AES.decrypt(str, key).toString(CryptoJS.enc.Utf8);
          }
      } catch(e) {}
      return "";
  }
}
